where ls.DEL_AT = 'N'

/*대상 검색*/

    AND t.HDQR_BOB_DCD = #{searchTarget}


/*구분 검색*/

    AND t.LEARNING_TYPE = #{searchLearningType}



    AND (ls.SCHED_NM LIKE CONCAT('%', #{searchKeyword}, '%')
    OR t.TEMPLATE_NAME LIKE CONCAT('%', #{searchKeyword}, '%')
    OR hm.MEM_NAME LIKE CONCAT('%', #{searchKeyword}, '%'))

